// Hexagon Egg — turquoise/coral nested diffs
speed = 0.5

// --- Audio helpers (smoothed envelopes)
AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

const rampMask = () => Math.min(1, time * 0.8);
const d1 = (s=2.0) => Math.sin(time * s);
const d2 = (s=1.0) => Math.cos(time * s);

// --- LAYER: Hexagon egg structure (o2)
// turquoise base: (0.3, 1.2, 0.9)  coral accents: (1.0, 0.4, 0.3)
shape(6, 0.18, 0.3).color(0.3, 1.2, 0.9)
  .diff(
    shape(6, 0.5, 0.1)
    .scrollX(0.06).rotate(() => time / 8)
    .color(1.0, 0.4, 0.3)
  )
  .diff(
    shape(6, 0.4, 0.05)
    .scrollX(0.12).rotate(() => time / 14)
    .color(0.9, 0.5, 0.35)
  )
  .diff(
    shape(6, 0.32, 0.02)
    .scrollX(0.18).rotate(() => time / 20)
    .color(0.25, 0.9, 0.75)
  )
  .diff(
    shape(6, 0.22, 0.01)
    .scrollX(0.24).rotate(() => time / 28)
    .color(0.85, 0.45, 0.3)
  )
  .diff(
    shape(6, 0.14, 0.005)
    .scrollX(0.30).rotate(() => time / 36)
    .color(0.2, 0.8, 0.65)
  )
  .modulateScale(
    shape(6, 1.8, 0).scrollX(0.06).rotate(() => time / 8),
    () => Math.sin(time / 4) * 0.22 + 0.18
  )
  .scale(0.07, 1.5, 1)
  .saturate(() => 1.1 + mid() * 0.15)
  .out(o2)

// --- LAYER: Osc texture bed (o1)
osc(() => 5.5 + 0.8 * d1(0.012), () => 0.12 + 0.03 * low(), () => 0.7 + 0.3 * high())
  .rotate(() => 0.005 * time + 0.02 * d1(0.008))
  .modulate(
    noise(() => 1.8 + 0.6 * mid(), 0.04 + 0.02 * low()),
    () => 0.14 + 0.06 * amp()
  )
  .color(
    () => 0.1 + 0.08 * low(),
    () => 0.55 + 0.18 * mid(),
    () => 0.7 + 0.1 * high()
  )
  .saturate(() => 0.04 + 0.08 * amp())
  .contrast(() => 1.01 + 0.02 * mid())
  .out(o1)

// --- Voronoi accent texture
const vTex = () =>
  voronoi(() => 4.0 + 60 * d1(0.006), () => 0.02 + 0.015 * mid(), 3.0)
    .invert()
    .color(0.08, 0.25, 0.2)
    .brightness(0.04)
    .modulate(noise(0.12, 0.018), 0.06);

// --- Composite: o1 base + o2 hex gated by luma (o3)
src(o1)
  .layer(src(o2).luma(0.5, 0.15).scale(1.005))
  .modulateScale(vTex(), () => 0.018 + 0.015 * amp())
  .out(o3)

// --- Feedback: o3 composited with masked self-feedback on o0
src(o3)
  .blend(src(o0), () => rampMask() * (0.18 + 0.14 * amp()))
  .modulateScale(noise(() => 1.2 + 0.5 * mid(), 0.07), () => 0.004 + low() * 0.002)
  .modulateRotate(noise(0.8, 0.025), () => 0.0018 + high() * 0.001)
  .hue(() => 0.003 * d1(0.005))
  .brightness(() => 0.012 + 0.015 * amp())
  .out(o0)

// --- Chromatic aberration + color cycling
src(o0).r().scrollX(() => 0.0008 + 0.001 * low()).scrollY(() => 0.0005 + 0.0006 * mid()).color(1.05, 0.08, 0.12)
  .add(
    src(o0).g().scrollX(() => -(0.0007 + 0.0008 * low())).scrollY(() => -(0.0004 + 0.0004 * mid())).color(0.1, 1.0, 0.5),
    0.92
  )
  .add(
    src(o0).b().scrollY(() => 0.0007 + 0.0008 * amp()).color(0.06, 0.18, 0.95),
    0.93
  )
  .colorama(() => 0.001 + 0.0015 * amp())
  .contrast(1.02)
  .saturate(() => 1.08 + low() * 0.1)
  .out();
